/* Test driver */
import java.util.List;
public class Main {
    public static void main(String[] args) {
        Scheduler s = new Scheduler(1);
        Task t1 = new SimpleTask("t1", TaskPriority.LOW, "first");
        Task t2 = new SimpleTask("t2", TaskPriority.HIGH, "second");
        s.submit(t1);
        s.submit(t2);
        s.addDependency(t2, t1);
        s.runAll();
        List<TaskResult> rs = s.getResults();
        boolean order = rs.size() == 2 && rs.get(0).getTaskId().equals(t1.getTaskId()) && rs.get(1).getTaskId().equals(t2.getTaskId());
        System.out.println(order ? "OK_ORDER_T1_FIRST" : "FAIL");
        System.out.println(t1.getState() == Task.State.COMPLETED && t2.getState() == Task.State.COMPLETED ? "OK_BOTH_DONE" : "FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Scheduler s = new Scheduler(1);
        Task t1 = new SimpleTask("t1", TaskPriority.LOW, "cancel me");
        Task t2 = new SimpleTask("t2", TaskPriority.MEDIUM, "run me");
        s.submit(t1);
        s.submit(t2);
        s.cancel(t1);
        s.runAll();
        System.out.println(t1.getState() == Task.State.CANCELLED ? "OK_T1_CANCELLED" : "FAIL");
        System.out.println(t2.getState() == Task.State.COMPLETED ? "OK_T2_DONE" : "FAIL");
    }
}

