import java.util.List;
public class Main {
    public static void main(String[] args) {
        Scheduler s = new Scheduler(1, new FifoSchedulingStrategy());
        Task low1 = new SimpleTask("first", TaskPriority.LOW, "submitted first");
        Task crit2 = new SimpleTask("second", TaskPriority.CRITICAL, "submitted second");
        s.submit(low1);
        s.submit(crit2);
        s.runAll();
        List<TaskResult> rs = s.getResults();
        boolean order = rs.size() == 2 && rs.get(0).getTaskId().equals(low1.getTaskId());
        System.out.println(order ? "OK_FIFO_FIRST_FIRST" : "FAIL");
        System.out.println(s.getSchedulingStrategy().name().equals("FIFO") ? "OK_STRAT_FIFO" : "FAIL");
    }
}

